#' @return the import context (See ImportContext class)
#' @export
import_context_ROS_LL_v3_2_1 <- function(file, connection, extra_data_tables, timestamp) {
  import_context(ROS_LL_v3_2_1_MODEL, file, connection, extra_data_tables, timestamp)
}
